-- Test script for development.

CREATE VIEW foo AS
    SELECT v::INTEGER AS x, (sin(v / 50000.0) * 100 + 100)::INTEGER AS y, (random() * 10)::INTEGER as cat10, (random() * 100)::INTEGER as cat100
    FROM generate_series(0, 1000000) AS a(v);

VIZ foo USING TABLE (
    pos = (r = 0, c = 0, w = 12, h = 4)
);
VIZ foo USING LINE(
    title = 'Line Chart',
    pos = (r = 4, c = 0, w = 6, h = 4)
);
VIZ foo USING SCATTER(
    title = 'Scatter Chart',
    pos = (r = 4, c = 6, w = 6, h = 4)
);
